
import base64, os, glob, shutil, subprocess, sys

AGENT = "/opt/polymarket-agent"

# Write the fixed autotrader.py from base64
content = base64.b64decode("").decode()
with open(f"{AGENT}/autotrader.py", "w") as f:
    f.write(content)
print(f"autotrader.py written: {len(content)} chars")

# Clear ALL pycache
removed = 0
for pyc in glob.glob(f"{AGENT}/**/*.pyc", recursive=True):
    try: os.remove(pyc); removed += 1
    except: pass
for d in glob.glob(f"{AGENT}/**/__pycache__", recursive=True):
    try: shutil.rmtree(d); removed += 1
    except: pass
print(f"Cleared {removed} cached files")

# Verify
with open(f"{AGENT}/autotrader.py") as f:
    c = f.read()
print(f"_THESIS_BLACKLIST: {'_THESIS_BLACKLIST' in c}")
print(f"blue devils: {'blue devils' in c}")
print(f"connecticut huskies: {'connecticut huskies' in c}")
print("READY TO RESTART")
